import{_ as t,o,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"20. Redundancy And Associated Entitlements","description":"","frontmatter":{"title":"20. Redundancy And Associated Entitlements","eba":"Mental Health Services 2024-2028","topics":["employment","redundancy","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/consultation-disputes/20-redundancy-and-associated-entitlements.md","filePath":"ebas/mental-health/common-terms/consultation-disputes/20-redundancy-and-associated-entitlements.md"}'),r={name:"ebas/mental-health/common-terms/consultation-disputes/20-redundancy-and-associated-entitlements.md"};function i(s,e,p,l,d,c){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="_20-redundancy-and-associated-entitlements" tabindex="-1">20. Redundancy And Associated Entitlements <a class="header-anchor" href="#_20-redundancy-and-associated-entitlements" aria-label="Permalink to &quot;20. Redundancy And Associated Entitlements&quot;">​</a></h1><p>A former section 97 Employee will not be entitled to the benefit of any entitlement under this clause where the same benefit (however titled) exists within <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/21-redeployment-former-s97-employees.html">clause 21</a>.</p><p><strong>20.1</strong> Arrangement This clause is arranged as follows:</p><p><strong>(a)</strong> Arrangement (subclause 20.1),</p><p><strong>(b)</strong> Definitions (subclause 20.2),</p><p><strong>(c)</strong> Redeployment (subclause 20.3),</p><p><strong>(d)</strong> Support to affected Employees (subclause 20.4),</p><p><strong>(e)</strong> Salary maintenance (subclause 20.6),</p><p><strong>(f)</strong> Relocation (subclause 20.7),</p><p><strong>(g)</strong> Employment terminates due to redundancy (subclause 20.8)</p><p><strong>(h)</strong> Exception to application of Victorian Government’s Policy with respect to severance pay (subclause 20.9)</p><p><strong>20.2</strong> Definitions</p><p><strong>(a)</strong> Affected Employee for this clause 20 means an Employee whose role will be redundant.</p><p><strong>(b)</strong> Comparable Role means an on-going role that:</p><p><strong>(i)</strong> is the same occupation as that of the Affected Employee’s redundant position or if not, is in an occupation acceptable to the Affected Employee; and</p><p><strong>(ii)</strong> is any of the following: <strong>(A)</strong> In the same clinical specialty as that of the Affected Employee’s former position <strong>(B)</strong> in a clinical specialty acceptable to the Affected Employee; or <strong>(C)</strong> a position that with the reasonable support described at 20.3(g), the Affected Employee could undertake; and</p><p><strong>(iii)</strong> is the same grade as the affected Employee’s redundant position</p><p><strong>(iv)</strong> takes into account the number of ordinary hours normally worked by the Affected Employee</p><p><strong>(v)</strong> is a Reasonable Distance from the Affected Employee&#39;s current work location</p><p><strong>(vi)</strong> takes the Affected Employee’s personal circumstances, including family responsibilities, into account; and</p><p><strong>(vii)</strong> takes account of health and safety considerations.</p><p><strong>(c)</strong> Consultation is as defined at <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/18-consultation.html">clause 18</a> (Consultation) of this Agreement.</p><p><strong>(d)</strong> Continuity of Service means that the service of the Affected Employee is treated as unbroken and that the cap on the transfer of personal leave at subclause 38A.9(b) does not apply. However, continuity of service is not broken where an Employer pays out accrued annual leave or long service leave upon termination in accordance with this Agreement.</p><p><strong>(e)</strong> Reasonable Distance shall have regard to the Affected Employee’s original work location, current home address, capacity of the Affected Employee to travel, additional travelling time, effects on the personal circumstances of the Affected Employee, including family commitments and responsibilities and other matters raised by the Affected Employee, or assistance provided by their Employer.</p><p><strong>(f)</strong> Redeployment Period means a period of 13 weeks from the time the Employer notifies the Affected Employee in writing that consultation under <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/18-consultation.html">clause 18</a> is complete and that the Redeployment Period has begun.</p><p><strong>(g)</strong> Redundancy means the Employer no longer requires the Affected Employee’s job to be performed by anyone because of changes in the operational requirements of the Employer’s enterprise.</p><p><strong>(h)</strong> Relocation means an Affected Employee is required to move to a different campus as a result of an organisational change on either a temporary or permanent basis.</p><p><strong>(i)</strong> Salary maintenance means an amount representing the difference between what the Affected Employee was normally paid immediately prior to the Affected Employee’s role being made redundant and the amount paid in the Affected Employee’s new role following redeployment.</p><p><strong>20.3</strong> Redeployment</p><p><strong>(a)</strong> An Affected Employee whose role will be redundant will be considered for redeployment during the Redeployment Period.</p><p><strong>(b)</strong> Employee to be advised in writing The Affected Employee must be advised in writing of:</p><p><strong>(i)</strong> the date the Affected Employee’s role is to be redundant,</p><p><strong>(ii)</strong> details of the redeployment process,</p><p><strong>(iii)</strong> the reasonable support that will be provided in accordance with subclause 20.3(g), and</p><p><strong>(iv)</strong> the Affected Employee’s rights and obligations.</p><p><strong>(c)</strong> Employer obligations The Employer will:</p><p><strong>(i)</strong> make every effort to redeploy the affected Employee to a Comparable Role in terms of classification, grade and income, including appointing a case manager to provide the Affected Employee with support and assistance;</p><p><strong>(ii)</strong> take into account the personal circumstances of the Affected Employee, including family commitments and responsibilities; and</p><p><strong>(iii)</strong> where the Employer is creating a new role/s substantially similar to the Affected Employee&#39;s redundant role; give priority to the redeployment of an Affected Employee/s to the new position/s before considering applicants that are not Affected Employees.</p><p>Example: The Employer needs fewer employees to do particular work and roles are being restructured to take this into account. In a &#39;spill and fill&#39;, the Employer will consider the Affected Employees for the new roles before other applicants.</p><p><strong>(d)</strong> Employee obligations The Employee must actively participate in the redeployment process including by:</p><p><strong>(i)</strong> identifying appropriate retraining needs</p><p><strong>(ii)</strong> developing a resume / CV to assist in securing redeployment</p><p><strong>(iii)</strong> actively monitoring and exploring appropriate redeployment opportunities and working with the appointed case manager.</p><p><strong>(e)</strong> Rejecting a Comparable Role Where an Affected Employee rejects an offer of redeployment to a comparable role (as defined), the Affected Employee may be ineligible for a departure package referred to at clause 20.8.</p><p><strong>(f)</strong> Temporary alternative duties An Affected Employee awaiting redeployment may be transferred to temporary alternative duties within the same campus, or where part of the Employee’s existing employment conditions (or by agreement) at another campus. Such temporary duties will be in accordance with the Affected Employee’s skills, experience, clinical area and profession.</p><p><strong>(g)</strong> Support for redeployment For an available role to be considered a comparable role, the Employer must provide the reasonable support necessary for the Affected Employee to perform the role which may include:</p><p><strong>(i)</strong> theory training relevant to the clinical area or environment of the role into which the Affected Employee is to be redeployed</p><p><strong>(ii)</strong> a defined period of up to 12 weeks in which the Affected Employee works in a supernumerary capacity</p><p><strong>(iii)</strong> support from educational staff in the clinical environment</p><p><strong>(iv)</strong> a review at 12 weeks or earlier to determine what, if any, further training is required.</p><p><strong>(h)</strong> Where no redeployment available If at any time during the Redeployment Period it is agreed that it is unlikely that the Affected Employee will be successfully redeployed, the Affected Employee may accept a redundancy package. Where this occurs, the Affected Employee will be entitled to an additional payment of the lesser of 13 weeks or the remaining Redeployment Period.</p><p><strong>(i)</strong> Non-Comparable Role An Affected Employee may agree to be redeployed to a role that is not a Comparable Role.</p><p><strong>20.4</strong> Support to Affected Employees</p><p><strong>(a)</strong> The Employer will provide Affected Employees whose position has been declared redundant with support and assistance which will include, where relevant:</p><p><strong>(i)</strong> counselling and support services</p><p><strong>(ii)</strong> retraining</p><p><strong>(iii)</strong> preparation of job applications</p><p><strong>(iv)</strong> interview coaching</p><p><strong>(v)</strong> time off to attend job interviews; and</p><p><strong>(vi)</strong> funding of independent financial advice for Employees eligible to receive a separation package.</p><p><strong>(b)</strong> Other assistance may include but is not limited to career planning.</p><p><strong>20.5</strong> Job Search Entitlement</p><p><strong>(a)</strong> An Employee given notice of termination in circumstances of redundancy must be allowed up to one day’s time off without loss of pay during each week of notice for the purpose of seeking other employment.</p><p><strong>(b)</strong> If the Employee has been allowed paid leave for more than one day during the notice period for the purpose of seeking other employment, the Employee must, at the request of the Employer, produce proof of attendance at an interview or they will not be entitled to payment for the time absent. For this purpose a statutory declaration is sufficient.</p><p><strong>20.6</strong> Salary Maintenance</p><p><strong>(a)</strong> Entitlement to salary maintenance An Affected Employee who is successfully redeployed will be entitled to salary maintenance where the Affected Employee’s pay is reduced because the new role:</p><p><strong>(i)</strong> is a lower grade</p><p><strong>(ii)</strong> involves working fewer hours; and/or</p><p><strong>(iii)</strong> removes eligibility for penalties, loadings and the like.</p><p><strong>(b)</strong> Period of salary maintenance Salary maintenance will be for a period of 52 weeks from the date the Affected Employee is redeployed except where the Affected Employee:</p><p><strong>(i)</strong> accepts another position within the salary maintenance period, and</p><p><strong>(ii)</strong> is paid in the other position an amount equal to or greater than the role that was made redundant.</p><p><strong>(c)</strong> Preservation of accrued leave An Affected Employee entitled to salary maintenance will have:</p><p><strong>(i)</strong> their long service leave and annual leave accruals preserved before redeployment. Specifically, the value of the leave immediately prior to redeployment will not be reduced because of redeployment; and</p><p><strong>(ii)</strong> their personal leave preserved in hours.</p><p><strong>20.7</strong> Relocation</p><p><strong>(a)</strong> Employer to advise in writing of relocation As soon as practicable but no less than seven (7) days after a decision is made by the Employer to temporarily or permanently relocate an Affected Employee, the Employer will advise the Affected Employee in writing of the decision, the proposed timing of the relocation and any other alternatives available to the Affected Employee. In addition, the Employer will:</p><p><strong>(i)</strong> ensure the relocation is a Reasonable Distance, unless otherwise agreed</p><p><strong>(ii)</strong> ensure that the Affected Employee is provided with information on the new location’s amenities, layout and local operations prior to the relocation, and</p><p><strong>(iii)</strong> consult with the Union regarding the content of such information.</p><p><strong>(b)</strong> Entitlement to relocation allowance</p><p>An Affected Employee is entitled to relocation allowance where permanent or temporary relocation results in additional cost to the Affected Employee for travel and / or other expenses.</p><p><strong>(c)</strong> Employee to provide written estimate The Affected Employee must make written application to the Employer with a written estimate of the additional travelling cost and other expenses for the period of redeployment up to a maximum of 12 months.</p><p><strong>(d)</strong> Payment</p><p><strong>(i)</strong> The Employer will pay the Affected Employee a relocation allowance, up to $1900.00 based on the written estimate of the Affected Employee referred to at (c) where the Employer accepts that estimate represents the additional cost to the Affected Employee. The allowance shall be paid as a lump sum</p><p><strong>(ii)</strong> When considering the Affected Employee’s estimate, the Employer may have regard to the Reasonable Distance</p><p><strong>(iii)</strong> In the event of a dispute about the Affected Employee&#39;s estimate it will be resolved under <a href="/eba/ebas/mental-health/common-terms/consultation-disputes/22-disputes-resolution-procedure.html">clause 22</a> – Dispute Resolution Procedure.</p><p><strong>(e)</strong> Exceptions An Affected Employee is not entitled to the relocation allowance if the site or campus to which the Affected Employee is being relocated is a location to which they can be expected to be deployed as part of their existing employment conditions.</p><p><strong>(f)</strong> Fixed term Employees not excluded An Affected Employee on a fixed term contract who is relocated will be covered by the terms of this clause for the duration of the fixed term contract.</p><p><strong>20.8</strong> Employment terminates due to redundancy The Victorian Government’s policy with respect to public sector redundancy and the entitlements upon termination of employment as a result of redundancy are set out in the Public Sector Industrial Relations Policies 2015. The policy as at the time this Agreement comes into operation applies to Employees but does not form part of this Agreement.</p><p><strong>20.9</strong> Exception to application of Victorian Government’s policy with respect to severance pay</p><p><strong>(a)</strong> Where the Affected Employee’s Employer secures a comparable role (as defined) with another Employer covered by this Agreement, which:</p><p><strong>(i)</strong> is within a Reasonable Distance of the work site of the redundant position</p><p><strong>(ii)</strong> provides Continuity of Service</p><p><strong>(iii)</strong> where the comparable role results in a loss of income, salary maintenance at subclause 20.6 will apply; and</p><p><strong>(iv)</strong> where relevant, consistent with the financial and other support provided to an internal redeployee the Employee will be considered successfully redeployed as though the employment was with the same Employer and no severance pay will apply.</p><p>Plain language terms: redundancy pay, retrenchment, position made redundant.</p>',98)])])}const f=t(r,[["render",i]]);export{h as __pageData,f as default};
